-- Sync sessions_used + status
WITH counts AS (
  SELECT package_id, COUNT(*) AS done_count
    FROM appointments
   WHERE status='done' AND package_id IS NOT NULL
     AND start_time >= '2025-12-01' AND start_time < '2026-04-01'
   GROUP BY package_id
)
UPDATE packages p
   SET sessions_used = c.done_count,
       status = CASE WHEN c.done_count >= p.total_sessions THEN 'completed'::package_status ELSE 'active'::package_status END
  FROM counts c
 WHERE p.id = c.package_id;

-- Revenue: package-linked
INSERT INTO revenue_entries (appointment_id, client_id, package_id, amount, recognized_at)
SELECT a.id, a.client_id, a.package_id,
       (p.total_paid::numeric / NULLIF(p.total_sessions,0)::numeric),
       a.start_time
  FROM appointments a
  JOIN packages p ON p.id = a.package_id
 WHERE a.status='done'
   AND a.start_time >= '2025-12-01' AND a.start_time < '2026-04-01'
   AND a.package_id IS NOT NULL
   AND NOT EXISTS (SELECT 1 FROM revenue_entries r WHERE r.appointment_id = a.id);

-- Revenue: standalone
INSERT INTO revenue_entries (appointment_id, client_id, package_id, amount, recognized_at)
SELECT a.id, a.client_id, NULL,
       CASE a.type WHEN 'medical_diagnosis' THEN 200 WHEN 'physio_diagnosis' THEN 150 WHEN 'recovery' THEN 70 ELSE 0 END,
       a.start_time
  FROM appointments a
 WHERE a.status='done'
   AND a.start_time >= '2025-12-01' AND a.start_time < '2026-04-01'
   AND a.package_id IS NULL
   AND NOT EXISTS (SELECT 1 FROM revenue_entries r WHERE r.appointment_id = a.id);

-- Mirror revenue_amount on appointments
UPDATE appointments a
   SET revenue_amount = r.amount
  FROM revenue_entries r
 WHERE r.appointment_id = a.id
   AND a.start_time >= '2025-12-01' AND a.start_time < '2026-04-01';
